-- Map billing items to their service IDs
-- BI002697 (Nu-Dev) -> S7428
-- BI002684 (TYS Molendinar) -> S7429
-- BI002685 (Zam Coomera Square) -> S7430
-- BI002686 (Zam Marrickville) -> S7431
-- BI00007 (Zambrero Karratha) -> S0423 (already has revenue)
-- BI00144 (Zambrero Brabham) -> S0016 (already has revenue)
-- BI00162 (Ma Pa Me) -> S1106 (already has revenue)
-- BI002691 (Jack Green) -> no service (one-off hardware)

-- Update billing items with service assignments
UPDATE billing_items SET serviceExternalId = 'S7428', matchStatus = 'service-matched' WHERE externalId = 'BI002697';
UPDATE billing_items SET serviceExternalId = 'S7429', matchStatus = 'service-matched' WHERE externalId = 'BI002684';
UPDATE billing_items SET serviceExternalId = 'S7430', matchStatus = 'service-matched' WHERE externalId = 'BI002685';
UPDATE billing_items SET serviceExternalId = 'S7431', matchStatus = 'service-matched' WHERE externalId = 'BI002686';
UPDATE billing_items SET serviceExternalId = 'S0423', matchStatus = 'service-matched' WHERE externalId = 'BI00007';
UPDATE billing_items SET serviceExternalId = 'S0016', matchStatus = 'service-matched' WHERE externalId = 'BI00144';
UPDATE billing_items SET serviceExternalId = 'S1106', matchStatus = 'service-matched' WHERE externalId = 'BI00162';

-- Jack Green is a one-off hardware item - mark as customer-matched (no service)
UPDATE billing_items SET matchStatus = 'customer-matched' WHERE externalId = 'BI002691';

-- Create service_billing_assignments for the 7 service-matched items
INSERT INTO service_billing_assignments (serviceExternalId, billingItemExternalId, assignmentType, createdAt)
VALUES
  ('S7428', 'BI002697', 'revenue', NOW()),
  ('S7429', 'BI002684', 'revenue', NOW()),
  ('S7430', 'BI002685', 'revenue', NOW()),
  ('S7431', 'BI002686', 'revenue', NOW()),
  ('S0423', 'BI00007', 'revenue', NOW()),
  ('S0016', 'BI00144', 'revenue', NOW()),
  ('S1106', 'BI00162', 'revenue', NOW());

-- Verify no more unmatched items
SELECT COUNT(*) as remaining_unmatched FROM billing_items WHERE matchStatus = 'unmatched';

